import java.util.*;
import java.util.stream.*;

public class Main {
    static final class Range {
        private final int low; private final int high;
        Range(int low, int high) { if (low > high) throw new IllegalArgumentException(); this.low = low; this.high = high; }
        boolean contains(int value) { return value >= low && value <= high; }
    }

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        int low = input.nextInt(), high = input.nextInt(), probe = input.nextInt();
        try { System.out.println(new Range(low, high).contains(probe) ? "contains" : "outside"); }
        catch (IllegalArgumentException error) { System.out.println("invalid"); }
    }
}
